133→function callClaudeOnce(prompt) {
134→  return new Promise((resolve, reject) => {
135→    const body = JSON.stringify({
136→      model: CLAUDE_MODEL,
137→      max_tokens: 2048,
138→      messages: [{ role: "user", content: prompt }],
139→    });
140→
141→    const url = new URL(CLAUDE_PROXY_URL);
142→    const req = http.request(
143→      {
144→        hostname: url.hostname,
145→        port: url.port,
146→        path: url.pathname,
147→        method: "POST",
148→        headers: {
149→          "Content-Type": "application/json",
150→          "x-api-key": "placeholder",
151→          "anthropic-version": "2023-06-01",
152→          "Content-Length": Buffer.byteLength(body),
153→        },
154→        timeout: 60000,
155→      },
156→      (res) => {
157→        const statusCode = res.statusCode;
158→        const chunks = [];
159→        res.on("data", (c) => chunks.push(c));
160→        res.on("end", () => {
161→          try {
162→            const data = JSON.parse(Buffer.concat(chunks).toString());
163→            if (statusCode >= 400 && statusCode < 500) {
164→              // 4xx — client error, not retryable
165→              reject(Object.assign(new Error(`Claude API ${statusCode}: ${JSON.stringify(data.error || data)}`), { retryable: false }));
166→              return;
167→            }
168→            if (statusCode >= 500) {
169→              reject(Object.assign(new Error(`Claude API ${statusCode}: ${JSON.stringify(data.error || data)}`), { retryable: true }));
170→              return;
171→            }
172→            if (data.error) {
173→              reject(Object.assign(new Error(`Claude API error: ${JSON.stringify(data.error)}`), { retryable: false }));
174→              return;
175→            }
176→            const text = data.content?.[0]?.text || "";
177→            resolve(text);
178→          } catch (e) {
179→            reject(Object.assign(new Error(`Failed to parse Claude response: ${e.message}`), { retryable: true }));
180→          }
181→        });
182→      }
183→    );
184→    req.on("error", (e) => reject(Object.assign(e, { retryable: true })));
185→    req.on("timeout", () => { req.destroy(); reject(Object.assign(new Error("Claude API timeout"), { retryable: true })); });
186→    req.write(body);
187→    req.end();
188→  });
189→}
