191→async function callClaude(prompt) {
192→  const MAX_ATTEMPTS = 3;
193→  const BASE_DELAY_MS = 2000;
194→  for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
195→    try {
196→      return await callClaudeOnce(prompt);
197→    } catch (e) {
198→      if (!e.retryable || attempt === MAX_ATTEMPTS) throw e;
199→      const delay = BASE_DELAY_MS * Math.pow(2, attempt - 1); // 2s, 4s, 8s
200→      console.log(`    [RETRY] Claude API attempt ${attempt}/${MAX_ATTEMPTS} failed: ${e.message} — retrying in ${delay / 1000}s...`);
201→      await new Promise((r) => setTimeout(r, delay));
202→    }
203→  }
204→}
