406→/**
407→ * 从修复前后的 text_normalized 提取精确的替换对。
408→ * 策略：按中文句号/逗号分段对齐，找出不同的段落，提取 before→after。
409→ */
410→function extractDiffPairs(before, after) {
411→  if (before === after) return [];
412→
413→  // 按标点分段
414→  const splitSegs = (t) => t.split(/(?<=[。，、；！？,.])/);
415→  const segsA = splitSegs(before);
416→  const segsB = splitSegs(after);
417→
418→  const pairs = [];
419→  const minLen = Math.min(segsA.length, segsB.length);
420→
421→  for (let i = 0; i < minLen; i++) {
422→    const a = segsA[i].trim();
423→    const b = segsB[i].trim();
424→    if (a !== b && a.length > 0 && b.length > 0) {
425→      // 进一步缩小差异范围：找最长公共前缀和后缀
426→      let prefixLen = 0;
427→      while (prefixLen < a.length && prefixLen < b.length && a[prefixLen] === b[prefixLen]) prefixLen++;
428→      let suffixLen = 0;
429→      while (suffixLen < a.length - prefixLen && suffixLen < b.length - prefixLen &&
430→             a[a.length - 1 - suffixLen] === b[b.length - 1 - suffixLen]) suffixLen++;
431→
432→      const origPart = a.slice(prefixLen, a.length - suffixLen);
433→      const fixedPart = b.slice(prefixLen, b.length - suffixLen);
434→
435→      if (origPart && fixedPart && origPart !== fixedPart) {
436→        pairs.push({ original: origPart, fixed: fixedPart });
437→      }
438→    }
439→  }
440→
441→  return pairs;
442→}
