444→function parseJSON(text) {
445→  try {
446→    return JSON.parse(text);
447→  } catch {
448→    // 尝试从 markdown code block 提取
449→    const match = text.match(/```(?:json)?\s*([\s\S]*?)```/);
450→    if (match) return JSON.parse(match[1]);
451→    // 尝试提取裸 JSON
452→    const match2 = text.match(/\{[\s\S]*\}/);
453→    if (match2) return JSON.parse(match2[0]);
454→    throw new Error("Cannot parse JSON from LLM response");
455→  }
456→}
